#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int t, n;
    scanf("%d", &t);
    while (t--) {
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, n, sizeof(int), compare);
        int turns = 0;
        for (int i = 0; i < n; i++) {
            turns++;
        }
        printf("%d\n", turns);
    }
    return 0;
}

